import React, { useState } from 'react';
import { GoogleGenAI, Type } from '@google/genai';

const Experience: React.FC = () => {
  const [prompt, setPrompt] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const [result, setResult] = useState<{ title: string; narrative: string } | null>(null);

  const handleSeekInspiration = async () => {
    if (!prompt.trim()) return;

    setIsLoading(true);
    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: `Provide a poetic and artistic creative direction for: "${prompt}". Focus on mood, texture, and visual atmosphere.`,
        config: {
          responseMimeType: 'application/json',
          responseSchema: {
            type: Type.OBJECT,
            properties: {
              title: { type: Type.STRING, description: 'A short, elegant title for the vision.' },
              narrative: { type: Type.STRING, description: 'A 2-3 sentence evocative description.' }
            },
            required: ['title', 'narrative']
          }
        }
      });

      const data = JSON.parse(response.text.trim());
      setResult(data);
    } catch (error) {
      console.error('Inspiration flow failed', error);
      setResult({
        title: "A Quiet Moment",
        narrative: "The vision is temporarily veiled. Let us breathe and try again in a moment of clarity."
      });
    } finally {
      setIsLoading(false);
    }
  };

  return (
    <div className="py-32 bg-lumina-charcoal text-lumina-cream">
      <div className="max-w-4xl mx-auto px-6 text-center">
        <h2 className="text-sm tracking-[0.4em] uppercase text-lumina-gold font-bold mb-4">The Interactive Atelier</h2>
        <h3 className="font-serif text-4xl md:text-5xl mb-12">Consult Your Muse</h3>

        <div className="bg-white/5 border border-white/10 p-8 md:p-12 backdrop-blur-sm relative">
          <p className="text-lumina-muted mb-10 italic">
            Describe a feeling, a place, or a color. Let the Lumina engine weave a visual narrative for your next masterpiece.
          </p>

          <div className="space-y-6">
            <textarea 
              value={prompt}
              onChange={(e) => setPrompt(e.target.value)}
              placeholder="e.g., The scent of rain on warm pavement at dusk..."
              className="w-full bg-transparent border-b border-white/20 py-4 text-xl font-serif focus:border-lumina-gold outline-none transition-colors resize-none placeholder:text-white/10"
              rows={2}
            />

            <button 
              onClick={handleSeekInspiration}
              disabled={isLoading || !prompt}
              className={`px-12 py-5 bg-lumina-gold text-lumina-charcoal text-sm tracking-widest uppercase font-bold hover:brightness-110 transition-all ${isLoading ? 'opacity-50 cursor-not-allowed' : ''}`}
            >
              {isLoading ? 'Consulting...' : 'Reveal Vision'}
            </button>
          </div>

          {result && (
            <div className="mt-16 text-left border-t border-white/10 pt-10 fade-in">
              <h4 className="text-xs tracking-[0.3em] uppercase text-lumina-gold mb-4">The Revealed Path</h4>
              <h5 className="font-serif text-3xl mb-4 italic">{result.title}</h5>
              <p className="text-lg text-lumina-muted leading-relaxed font-light">
                {result.narrative}
              </p>
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

export default Experience;

